1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
14	
15	const BASE_PRICES: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
25	const BLOCK_PRICE: Record<string, number> = {
26	  rune: 60,
27	  moonstone: 60,
28	};
29	
30	export interface QuoteContext {
31	  previousQuoteCount?: number;
32	}
33	
34	export function quote(customer: Customer, items: Item[], context?: QuoteContext): number {
35	  let total = 0;
36	  const componentCounts: Record<string, number> = {};
37	  for (const item of items) {
38	    if (COMPONENT_TYPES.has(item.type)) {
39	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
40	      continue;
41	    }
42	    const base = BASE_PRICES[item.type] ?? 0;
43	    const curse = item.cursed ? base * 0.5 : 0;
44	    const highEnchant = (item.enchantment ?? 0) >= 5 ? base * 0.3 : 0;
45	    total += base + curse + highEnchant + base * FIRST_INSURANCE_SURCHARGE_RATE;
46	  }
47	  for (const type of Object.keys(componentCounts)) {
48	    const count = componentCounts[type];
49	    const unitPrice = BASE_PRICES[type] ?? 0;
50	    const base = count === 3 ? BLOCK_PRICE[type] : unitPrice * count;
51	    total += base + base * FIRST_INSURANCE_SURCHARGE_RATE;
52	  }
53	  if (customer.yearsWithMHPCO >= 2) {
54	    total = total * 0.8;
55	  }
56	  if ((context?.previousQuoteCount ?? 0) > 0) {
57	    total = total * 0.85;
58	  }
59	  total += PROCESSING_FEE;
60	  return Math.ceil(total);
61	}
62	
63	export function claim(): unknown {
64	  return undefined;
65	}
